    var chainPolicy \= new X509ChainPolicy
    {
        // ... revocation check configuration omitted for brevity

        // explicitly disable AIA (default is \`false\`)
        DisableCertificateDownloads \= true,

        // Add any necessary intermediates to the ExtraStore
        ExtraStore \= new X509Certificate2Collection(intermediateCertificate),

        // if your scenario uses client certificates issued by a private root CA, you should also specify custom trust
        TrustMode \= X509ChainTrustMode.CustomTrustRoot,
        CustomTrustStore \= new X509Certificate2Collection(rootCertificate)
    };

    var sslStream \= new SslStream(networkStream);

    sslStream.AuthenticateAsServer(new SslServerAuthenticationOptions
    {
        ServerCertificateContext \= serverCertificateContext,
        ClientCertificateRequred \= true,
        CertificateChainPolicy \= chainPolicy

        // Note: CertificateRevocationCheckMode property is superseeded by configuration in the chainPolicy
        // CertificateRevocationCheckMode = X509RevocationMode.Online // has no effect
    });

3.  **Explicitly allow AIA downloads (not recommended)**: If necessary, you can restore the previous behavior by setting `X509ChainPolicy.DisableCertificateDownloads` to `false`. However, this approach is not recommended due to the associated performance and security risks.

    var chainPolicy \= new X509ChainPolicy
    {
        // ... other configuration omitted for brevity
        DisableCertificateDownloads \= false // allow AIA downloads
    };

    var sslStream \= new SslStream(networkStream);

    sslStream.AuthenticateAsServer(new SslServerAuthenticationOptions
    {
        ServerCertificateContext \= serverCertificateContext,
        ClientCertificateRequred \= true,
        CertificateChainPolicy \= chainPolicy

        // Note: CertificateRevocationCheckMode property is superseeded by configuration in the chainPolicy
        // CertificateRevocationCheckMode = X509RevocationMode.Online // has no effect
    });


